import React, { useState } from 'react';
import DocumentInput from './components/DocumentInput';
import FormFillOutput from './components/FormFillOutput';
import './styles/claude-theme.css';

const App: React.FC = () => {
    const [formData, setFormData] = useState<any>(null);

    const handleDocumentSubmit = (data: any) => {
        setFormData(data);
    };

    return (
        <div className="app-container">
            <h1>Claude Form Fill Application</h1>
            <DocumentInput onSubmit={handleDocumentSubmit} />
            {formData && <FormFillOutput data={formData} />}
        </div>
    );
};

export default App;
